/// <summary>
/// get metadata class to process sales order lines or transfer order shipments
/// </summary>
/// <param name = "_transType">InventTransType _transType</param>
/// <returns>ITMLineCreate</returns>
public static ITMLineCreate newLineCreateFromInventTransTypeOutETG(InventTransType _transType)
{
    ITMLineCreate instance;
    SysPluginMetadataCollection metadataCollection = new SysPluginMetadataCollection();

    metadataCollection.SetManagedValue(
        enumstr(InventTransType),
        enum2Symbol(enumNum(InventTransType), any2enum(_transType)));

    instance = SysPluginFactory::Instance(
        identifierStr(Dynamics.AX.Application),
        classStr(ITMLineCreate), 
        metadataCollection) as ITMLineCreate;

    if (!instance)
    {
        throw error(Error::wrongUseOfFunction(funcName()));
    }

    return instance;
}
